import{_ as e,o as a,c as t,ag as n}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Placement and Distribution","description":"","frontmatter":{},"headers":[],"relativePath":"en/industrial-practices/lighting/placement-distribution.md","filePath":"en/industrial-practices/lighting/placement-distribution.md"}'),r={name:"en/industrial-practices/lighting/placement-distribution.md"};function o(l,i,s,c,d,p){return a(),t("div",null,[...i[0]||(i[0]=[n('<h1 id="placement-and-distribution" tabindex="-1">Placement and Distribution <a class="header-anchor" href="#placement-and-distribution" aria-label="Permalink to &quot;Placement and Distribution&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Placement and distribution refer to how lighting fixtures are positioned and how light is spread across an industrial space.</p><p>Proper placement ensures that illumination is delivered where it is needed, while distribution determines how evenly light is applied across the area.</p><p>Both factors are critical to achieving effective and usable lighting.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of proper placement and distribution is to provide uniform visibility across the workspace.</p><p>This helps to:</p><ul><li>Eliminate dark areas and excessive shadows</li><li>Improve task visibility and accuracy</li><li>Reduce glare and visual discomfort</li><li>Ensure consistent lighting conditions</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Lighting placement is defined by the location and spacing of fixtures.</p><p>Distribution depends on the fixture design and how light is emitted.</p><p>Key aspects include:</p><ul><li>Mounting height, which affects coverage area and intensity</li><li>Spacing between fixtures to ensure uniform illumination</li><li>Beam angle and light pattern of the fixture</li><li>Orientation to avoid direct glare and shadows</li></ul><p>A well designed layout balances coverage and intensity to avoid over lighting or under lighting specific areas.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Placement and distribution are important in:</p><ul><li>Production areas with continuous operations</li><li>Warehouses with shelving and aisles</li><li>Control panels and workstations</li><li>Maintenance areas requiring detailed work</li><li>Outdoor spaces with wide coverage requirements</li></ul><p>Each application requires a different approach based on layout and task requirements.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li>Uniformity is more important than localized high intensity</li><li>Shadows must be minimized in work areas</li><li>Glare must be controlled to protect visibility</li><li>Fixture placement must consider obstacles such as equipment or structures</li><li>Mounting height must match the type of fixture and space</li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Uneven lighting creates fatigue and reduces efficiency</li><li>Fixtures placed too far apart create dark zones</li><li>Poor placement can hide important details or hazards</li><li>Task lighting should complement general lighting, not replace it</li><li>Always evaluate lighting from the operator point of view</li></ul>',23)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
